import { ThemeToggle } from "@/components/ThemeToggle";

const roles: { key: Role; label: string; desc: string; icon: any; email: string; password: string; tone: string; glow: string }[] = [
  { key: "admin", label: "Admin", desc: "Full system access", icon: Shield, email: "aarav@vibetechlabs.com", password: "admin@123", tone: "bg-sage-3d", glow: "hsl(140 40% 50% / 0.4)" },
  { key: "manager", label: "Manager", desc: "Team management", icon: UserCog, email: "priya@vibetechlabs.com", password: "manager@123", tone: "bg-peach-3d", glow: "hsl(22 70% 70% / 0.4)" },
  { key: "employee", label: "Employee", desc: "Self-service portal", icon: User, email: "rohan@vibetechlabs.com", password: "employee@123", tone: "bg-powder-3d", glow: "hsl(210 55% 70% / 0.4)" },
];

type Step = "creds" | "face" | "location" | "done";

export default function Login() {
  const user = useAuthStore((s) => s.user);
  const login = useAuthStore((s) => s.login);
  const navigate = useNavigate();

  const [step, setStep] = useState<Step>("creds");
  const [selected, setSelected] = useState<Role>("admin");
  const [email, setEmail] = useState(roles[0].email);
  const [password, setPassword] = useState(roles[0].password);
  const [loading, setLoading] = useState(false);

  const [faceProgress, setFaceProgress] = useState(0);
  const [locProgress, setLocProgress] = useState(0);
  const faceTimer = useRef<number | null>(null);
  const locTimer = useRef<number | null>(null);

  if (user) {
    return <Navigate to={user.role === "employee" ? "/employee" : "/admin"} replace />;
  }

  const handleSelect = (r: Role) => {
    setSelected(r);
    const found = roles.find((x) => x.key === r)!;
    setEmail(found.email);
    setPassword(found.password);
  };

  const copyCred = (text: string, label: string) => {
    navigator.clipboard.writeText(text);
    toast.success(`${label} copied`);
  };

  const handleCreds = (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setTimeout(() => {
      setLoading(false);
      setStep("face");
      runFaceScan();
    }, 500);
  };

  const runFaceScan = () => {
    setFaceProgress(0);
    if (faceTimer.current) window.clearInterval(faceTimer.current);
    faceTimer.current = window.setInterval(() => {
      setFaceProgress((p) => {
        if (p >= 100) {
          window.clearInterval(faceTimer.current!);
          setTimeout(() => {
            setStep("location");
            runLocation();
          }, 400);
          return 100;
        }
        return p + 4;
      });
    }, 70);
  };

  const runLocation = () => {
    setLocProgress(0);
    if (locTimer.current) window.clearInterval(locTimer.current);
    locTimer.current = window.setInterval(() => {
      setLocProgress((p) => {
        if (p >= 100) {
          window.clearInterval(locTimer.current!);
          setTimeout(() => {
            setStep("done");
            setTimeout(() => {
              login(selected);
              toast.success(`Welcome! Signed in as ${selected}`);
              navigate(selected === "employee" ? "/employee" : "/admin", { replace: true });
            }, 700);
          }, 400);
          return 100;
        }
        return p + 5;
      });
    }, 70);
  };

  useEffect(() => () => {
    if (faceTimer.current) window.clearInterval(faceTimer.current);
    if (locTimer.current) window.clearInterval(locTimer.current);
  }, []);

  return (
    <div className="min-h-screen grid lg:grid-cols-2 relative overflow-hidden bg-background">
      {/* Theme toggle */}
      <div className="absolute top-4 right-4 z-50">
        <ThemeToggle />
      </div>

      {/* ─── Animated gradient orbs backdrop ─── */}
      <div className="pointer-events-none absolute inset-0 overflow-hidden">
        <motion.div
          className="absolute -top-32 -left-32 w-[500px] h-[500px] rounded-full opacity-60"
          style={{ background: "radial-gradient(circle, hsl(140 40% 70% / 0.5), transparent 70%)" }}
          animate={{ x: [0, 40, 0], y: [0, 30, 0], scale: [1, 1.15, 1] }}
          transition={{ duration: 8, repeat: Infinity, ease: "easeInOut" }}
        />
        <motion.div
          className="absolute top-1/4 -right-24 w-[400px] h-[400px] rounded-full opacity-50"
          style={{ background: "radial-gradient(circle, hsl(22 80% 80% / 0.4), transparent 70%)" }}
          animate={{ x: [0, -30, 0], y: [0, 40, 0], scale: [1, 1.1, 1] }}
          transition={{ duration: 7, repeat: Infinity, ease: "easeInOut", delay: 1 }}
        />
        <motion.div
          className="absolute bottom-0 left-1/4 w-[350px] h-[350px] rounded-full opacity-45"
          style={{ background: "radial-gradient(circle, hsl(210 60% 80% / 0.35), transparent 70%)" }}
          animate={{ x: [0, 25, 0], y: [0, -35, 0], scale: [1, 1.08, 1] }}
          transition={{ duration: 9, repeat: Infinity, ease: "easeInOut", delay: 2 }}
        />
        <motion.div
          className="absolute top-2/3 left-12 w-[200px] h-[200px] rounded-full opacity-40"
